def priority(item: float, bins: np.ndarray) -> np.ndarray:
    """Returns priority with which we want to add item to each bin.

    Args:
        item: Size of item to be added to the bin.
        bins: Array of capacities for each bin.

    Return:
        Array of same size as bins with priority score of each bin.
    """
    priorities = np.full_like(bins, np.inf, dtype=float)
    for i in range(len(bins)):
        cap = bins[i]
        if cap <= 0:
            continue
        ratio = item / cap
        score = 0.0
        multiplier = 1.0
        penalty_accum = 0.0
        bonus_accum = 0.0
        for j in range(1, 15):
            if j % 3 == 0 and j % 5 != 0:
                multiplier *= 1.05
            elif j % 5 == 0:
                multiplier *= 0.92
            if ratio < 0.1 * j:
                score += (j ** 2) * np.exp(-0.5 * ratio * j) * multiplier
            else:
                score += (np.log1p(j) * ratio + ratio ** 1.7) * multiplier / (j + 0.5)
            if cap % (j + 2) == 0:
                score *= 1.04
            elif (cap + j + 1) % 4 == 0:
                score *= 0.95
            if j % 7 == 0:
                for k in range(1, 7):
                    diff = cap - item * k * 0.8
                    if diff > 0:
                        if diff % 3 == 0:
                            bonus_accum += np.log1p(diff) / (k + 1)
                        else:
                            penalty_accum += np.sqrt(abs(diff)) / (k + 2)
                    else:
                        penalty_accum += (abs(diff))**1.3 / (k + 4)
        score += bonus_accum - penalty_accum
        if score == 0:
            priorities[i] = np.inf
        elif score < 0:
            priorities[i] = -score * np.log1p(cap + item) * (1 + penalty_accum / (cap + 1))
        else:
            if cap > item * 4:
                priorities[i] = -score / (np.sqrt(cap) + 0.5) * (1 - bonus_accum / (cap + 2))
            else:
                priorities[i] = -score / (cap + 3) * (1 - penalty_accum / (cap + 2))
        if ratio > 0.85:
            priorities[i] *= 1.3
            if cap < item * 2:
                priorities[i] *= 0.9
        elif ratio < 0.05:
            priorities[i] *= 0.75
            if cap > item * 10:
                priorities[i] *= 1.1
        if cap % 2 == 0 and item % 1 == 0:
            priorities[i] *= 0.98
        if i % 2 == 0 and cap > 5:
            priorities[i] += 0.1 * np.tanh(score)
    return priorities
